package main

import (
    "encoding/json"
    "fmt"
    "net/http"
    "strconv"
    "sync"
)

// ---- Models ----
type Player struct {
    ID     int    `json:"id"`
    Name   string `json:"name"`
    Health int    `json:"health"`
    Attack int    `json:"attack"`
    Level  int    `json:"level"`
}

// ---- Repository (data layer) ----
type PlayerRepository struct {
    mu      sync.RWMutex
    players map[int]Player
    nextID  int
}

func NewPlayerRepository() *PlayerRepository {
    return &PlayerRepository{
        players: make(map[int]Player),
        nextID:  1,
    }
}

func (r *PlayerRepository) Create(name string, health, attack int) Player {
    r.mu.Lock()
    defer r.mu.Unlock()

    player := Player{
        ID:     r.nextID,
        Name:   name,
        Health: health,
        Attack: attack,
        Level:  1,
    }
    r.players[player.ID] = player
    r.nextID++
    return player
}

func (r *PlayerRepository) GetAll() []Player {
    r.mu.RLock()
    defer r.mu.RUnlock()

    players := make([]Player, 0, len(r.players))
    for _, p := range r.players {
        players = append(players, p)
    }
    return players
}

func (r *PlayerRepository) GetByID(id int) (Player, bool) {
    r.mu.RLock()
    defer r.mu.RUnlock()

    p, ok := r.players[id]
    return p, ok
}

func (r *PlayerRepository) Update(id int, name string, health, attack, level int) (Player, bool) {
    r.mu.Lock()
    defer r.mu.Unlock()

    p, ok := r.players[id]
    if !ok {
        return Player{}, false
    }

    if name != "" {
        p.Name = name
    }
    if health > 0 {
        p.Health = health
    }
    if attack > 0 {
        p.Attack = attack
    }
    if level > 0 {
        p.Level = level
    }

    r.players[id] = p
    return p, true
}

func (r *PlayerRepository) Delete(id int) bool {
    r.mu.Lock()
    defer r.mu.Unlock()

    _, ok := r.players[id]
    if !ok {
        return false
    }
    delete(r.players, id)
    return true
}

// ---- Response ----
type APIResponse struct {
    Success bool        `json:"success"`
    Message string      `json:"message"`
    Data    interface{} `json:"data,omitempty"`
}

// ---- Handlers ----
type PlayerHandler struct {
    repo *PlayerRepository
}

func NewPlayerHandler(repo *PlayerRepository) *PlayerHandler {
    return &PlayerHandler{repo: repo}
}

func (h *PlayerHandler) GetPlayers(w http.ResponseWriter, r *http.Request) {
    players := h.repo.GetAll()
    sendJSON(w, http.StatusOK, APIResponse{
        Success: true,
        Message: "Players retrieved",
        Data:    players,
    })
}

func (h *PlayerHandler) CreatePlayer(w http.ResponseWriter, r *http.Request) {
    var req struct {
        Name   string `json:"name"`
        Health int    `json:"health"`
        Attack int    `json:"attack"`
    }

    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        sendError(w, http.StatusBadRequest, "Invalid JSON")
        return
    }

    if req.Name == "" {
        sendError(w, http.StatusBadRequest, "Name is required")
        return
    }

    if req.Health == 0 {
        req.Health = 100
    }
    if req.Attack == 0 {
        req.Attack = 10
    }

    player := h.repo.Create(req.Name, req.Health, req.Attack)
    sendJSON(w, http.StatusCreated, APIResponse{
        Success: true,
        Message: "Player created",
        Data:    player,
    })
}

func (h *PlayerHandler) GetPlayer(w http.ResponseWriter, r *http.Request) {
    id, err := getIDFromPath(r.URL.Path)
    if err != nil {
        sendError(w, http.StatusBadRequest, "Invalid ID")
        return
    }

    player, ok := h.repo.GetByID(id)
    if !ok {
        sendError(w, http.StatusNotFound, "Player not found")
        return
    }

    sendJSON(w, http.StatusOK, APIResponse{
        Success: true,
        Message: "Player found",
        Data:    player,
    })
}

func (h *PlayerHandler) UpdatePlayer(w http.ResponseWriter, r *http.Request) {
    id, err := getIDFromPath(r.URL.Path)
    if err != nil {
        sendError(w, http.StatusBadRequest, "Invalid ID")
        return
    }

    var req struct {
        Name   string `json:"name"`
        Health int    `json:"health"`
        Attack int    `json:"attack"`
        Level  int    `json:"level"`
    }

    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        sendError(w, http.StatusBadRequest, "Invalid JSON")
        return
    }

    player, ok := h.repo.Update(id, req.Name, req.Health, req.Attack, req.Level)
    if !ok {
        sendError(w, http.StatusNotFound, "Player not found")
        return
    }

    sendJSON(w, http.StatusOK, APIResponse{
        Success: true,
        Message: "Player updated",
        Data:    player,
    })
}

func (h *PlayerHandler) DeletePlayer(w http.ResponseWriter, r *http.Request) {
    id, err := getIDFromPath(r.URL.Path)
    if err != nil {
        sendError(w, http.StatusBadRequest, "Invalid ID")
        return
    }

    if !h.repo.Delete(id) {
        sendError(w, http.StatusNotFound, "Player not found")
        return
    }

    sendJSON(w, http.StatusOK, APIResponse{
        Success: true,
        Message: "Player deleted",
    })
}

// ---- Helpers ----
func sendJSON(w http.ResponseWriter, status int, data interface{}) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(status)
    json.NewEncoder(w).Encode(data)
}

func sendError(w http.ResponseWriter, status int, message string) {
    sendJSON(w, status, APIResponse{
        Success: false,
        Message: message,
    })
}

func getIDFromPath(path string) (int, error) {
    // Expects /api/players/123
    // In a real app, use a router with path parameters
    // This is a simple version for demonstration
    return strconv.Atoi(path[len("/api/players/"):])
}

func main() {
    repo := NewPlayerRepository()
    handler := NewPlayerHandler(repo)

    // Seed data
    repo.Create("Hero", 100, 20)
    repo.Create("Aragorn", 120, 25)
    repo.Create("Gandalf", 80, 15)

    // ---- Routes ----
    http.HandleFunc("/api/players", func(w http.ResponseWriter, r *http.Request) {
        switch r.Method {
        case "GET":
            handler.GetPlayers(w, r)
        case "POST":
            handler.CreatePlayer(w, r)
        default:
            sendError(w, http.StatusMethodNotAllowed, "Method not allowed")
        }
    })

    http.HandleFunc("/api/players/", func(w http.ResponseWriter, r *http.Request) {
        switch r.Method {
        case "GET":
            handler.GetPlayer(w, r)
        case "PUT":
            handler.UpdatePlayer(w, r)
        case "DELETE":
            handler.DeletePlayer(w, r)
        default:
            sendError(w, http.StatusMethodNotAllowed, "Method not allowed")
        }
    })

    fmt.Println("Server starting on :8080")
    fmt.Println("Routes:")
    fmt.Println("  GET  /api/players")
    fmt.Println("  POST /api/players")
    fmt.Println("  GET  /api/players/{id}")
    fmt.Println("  PUT  /api/players/{id}")
    fmt.Println("  DELETE /api/players/{id}")

    http.ListenAndServe(":8080", nil)
}

