package main

import (
    "encoding/json"
    "fmt"
    "net/http"
    "strconv"
    "sync"
)

type Product struct {
    ID    int     `json:"id"`
    Name  string  `json:"name"`
    Price float64 `json:"price"`
}

type ProductRepository struct {
    mu       sync.RWMutex
    products map[int]Product
    nextID   int
}

func NewProductRepository() *ProductRepository {
    return &ProductRepository{
        products: make(map[int]Product),
        nextID:   1,
    }
}

func (r *ProductRepository) Create(name string, price float64) Product {
    r.mu.Lock()
    defer r.mu.Unlock()
    p := Product{ID: r.nextID, Name: name, Price: price}
    r.products[p.ID] = p
    r.nextID++
    return p
}

func (r *ProductRepository) GetAll() []Product {
    r.mu.RLock()
    defer r.mu.RUnlock()
    products := []Product{}
    for _, p := range r.products {
        products = append(products, p)
    }
    return products
}

func (r *ProductRepository) GetByID(id int) (Product, bool) {
    r.mu.RLock()
    defer r.mu.RUnlock()
    p, ok := r.products[id]
    return p, ok
}

func (r *ProductRepository) Delete(id int) bool {
    r.mu.Lock()
    defer r.mu.Unlock()
    _, ok := r.products[id]
    if !ok {
        return false
    }
    delete(r.products, id)
    return true
}

type APIResponse struct {
    Success bool        `json:"success"`
    Message string      `json:"message"`
    Data    interface{} `json:"data,omitempty"`
}

type ProductHandler struct {
    repo *ProductRepository
}

func NewProductHandler(repo *ProductRepository) *ProductHandler {
    return &ProductHandler{repo: repo}
}

func (h *ProductHandler) GetProducts(w http.ResponseWriter, r *http.Request) {
    products := h.repo.GetAll()
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(APIResponse{Success: true, Data: products})
}

func (h *ProductHandler) CreateProduct(w http.ResponseWriter, r *http.Request) {
    var req struct {
        Name  string  `json:"name"`
        Price float64 `json:"price"`
    }
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        w.Header().Set("Content-Type", "application/json")
        w.WriteHeader(http.StatusBadRequest)
        json.NewEncoder(w).Encode(APIResponse{Success: false, Message: "Invalid JSON"})
        return
    }
    p := h.repo.Create(req.Name, req.Price)
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(http.StatusCreated)
    json.NewEncoder(w).Encode(APIResponse{Success: true, Message: "Product created", Data: p})
}

func (h *ProductHandler) GetProduct(w http.ResponseWriter, r *http.Request) {
    id, _ := strconv.Atoi(r.URL.Path[len("/api/products/"):])
    p, ok := h.repo.GetByID(id)
    if !ok {
        w.Header().Set("Content-Type", "application/json")
        w.WriteHeader(http.StatusNotFound)
        json.NewEncoder(w).Encode(APIResponse{Success: false, Message: "Product not found"})
        return
    }
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(APIResponse{Success: true, Data: p})
}

func main() {
    repo := NewProductRepository()
    repo.Create("Sword", 50.0)
    repo.Create("Shield", 40.0)

    handler := NewProductHandler(repo)

    http.HandleFunc("/api/products", func(w http.ResponseWriter, r *http.Request) {
        if r.Method == "GET" {
            handler.GetProducts(w, r)
        } else if r.Method == "POST" {
            handler.CreateProduct(w, r)
        }
    })

    http.HandleFunc("/api/products/", func(w http.ResponseWriter, r *http.Request) {
        if r.Method == "GET" {
            handler.GetProduct(w, r)
        }
    })

    fmt.Println("Server starting on :8080")
    http.ListenAndServe(":8080", nil)
}
